package org.eclipse.jdt.internal.ui.preferences.cleanup;

import java.util.Map;
import org.eclipse.jdt.internal.ui.fix.AbstractCleanUp;
import org.eclipse.jdt.internal.ui.fix.Java50CleanUp;
import org.eclipse.jdt.internal.ui.fix.PotentialProgrammingProblemsCleanUpCore;
import org.eclipse.jdt.internal.ui.fix.UnimplementedCodeCleanUp; // Old class

// Dummy classes for compilation context
class AbstractCleanUpTabPage {}

package org.eclipse.jdt.internal.ui.fix;
import java.util.Map;
abstract class AbstractCleanUp {
    public AbstractCleanUp(Map<String, String> values) {}
}
class Java50CleanUp extends AbstractCleanUp {
    public Java50CleanUp(Map<String, String> values) { super(values); }
}
class PotentialProgrammingProblemsCleanUpCore extends AbstractCleanUp {
    public PotentialProgrammingProblemsCleanUpCore(Map<String, String> values) { super(values); }
}
class UnimplementedCodeCleanUp extends AbstractCleanUp {
    public UnimplementedCodeCleanUp(Map<String, String> values) { super(values); }
}

package org.eclipse.jdt.internal.ui.preferences.cleanup;

public final class MissingCodeTabPage extends AbstractCleanUpTabPage {
    protected AbstractCleanUp[] createPreviewCleanUps(Map<String, String> values) {
        return new AbstractCleanUp[] { new Java50CleanUp(values), new PotentialProgrammingProblemsCleanUpCore(values), new UnimplementedCodeCleanUp(values) };
    }
}

